from elasticsearch import Elasticsearch
from flask import Flask, request, jsonify

app = Flask(__name__)
es = Elasticsearch()

@app.route('/execute_script', methods=['POST'])
def execute_script():
    try:
        script_code = request.json['script']
        index_name = request.json.get('index', 'default-index')
        
        query_body = {
            "size": 0,
            "aggs": {
                "dynamic_script": {
                    "scripted_metric": {
                        "init_script": "state.values = []",
                        "map_script": script_code,
                        "combine_script": "return state.values",
                        "reduce_script": "return states"
                    }
                }
            }
        }
        
        response = es.search(index=index_name, body=query_body)
        return jsonify(response['aggregations']['dynamic_script']['value'])
    
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=True)